#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int* orders = (int*) malloc(M * sizeof(int));
        for (int i = 0; i < M; i++) {
            scanf("%d", &orders[i]);
        }
        int* tables = (int*) calloc(N, sizeof(int));
        int cleanCount = 0;
        for (int i = 0; i < M; i++) {
            int customer = orders[i];
            int allocated = 0;
            for (int j = 0; j < N; j++) {
                if (tables[j] == 0) {
                    tables[j] = customer;
                    allocated = 1;
                    cleanCount++;
                    break;
                }
            }
            if (!allocated) {
                for (int j = 0; j < N; j++) {
                    if (tables[j] != customer) {
                        tables[j] = customer;
                        cleanCount++;
                        break;
                    }
                }
            }
        }
        printf("%d\n", cleanCount);
        free(orders);
        free(tables);
    }
    return 0;
}

