        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            int[] orders = new int[M];
            for (int i = 0; i < M; i++) {
                orders[i] = scanner.nextInt();
            }
            int[] tables = new int[N];
            int cleanCount = 0;
            for (int i = 0; i < M; i++) {
                int customer = orders[i];
                boolean allocated = false;
                for (int j = 0; j < N; j++) {
                    if (tables[j] == 0) {
                        tables[j] = customer;
                        allocated = true;
                        cleanCount++;
                        break;
                    }
                }
                if (!allocated) {
                    for (int j = 0; j < N; j++) {
